import{_ as a,c as t,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Integración de plataformas: acceso a múltiples protocolos | Antigravity-Manager","description":"Aprende a integrar protocolos de plataformas en Antigravity Tools. Compatible con OpenAI, Anthropic, Gemini y otros 7 protocolos mediante API Gateway unificada.","frontmatter":{"title":"Integración de plataformas: acceso a múltiples protocolos | Antigravity-Manager","sidebarTitle":"Conecta tus plataformas de IA","subtitle":"Integración de plataformas: acceso a múltiples protocolos","description":"Aprende a integrar protocolos de plataformas en Antigravity Tools. Compatible con OpenAI, Anthropic, Gemini y otros 7 protocolos mediante API Gateway unificada.","order":200},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"es/lbjlaq/Antigravity-Manager/platforms/index.md"}'),r={name:"es/lbjlaq/Antigravity-Manager/platforms/index.md"};function n(d,e,s,c,l,p){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="plataformas-e-integraciones" tabindex="-1">Plataformas e integraciones <a class="header-anchor" href="#plataformas-e-integraciones" aria-label="Permalink to &quot;Plataformas e integraciones&quot;">​</a></h1><p>La capacidad principal de Antigravity Tools es convertir los protocolos de múltiples plataformas de IA en una API Gateway local unificada. Este capítulo detalla los métodos de integración para cada protocolo, sus límites de compatibilidad y las mejores prácticas.</p><h2 id="contenido-de-este-capitulo" tabindex="-1">Contenido de este capítulo <a class="header-anchor" href="#contenido-de-este-capitulo" aria-label="Permalink to &quot;Contenido de este capítulo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descripción</th></tr></thead><tbody><tr><td><a href="./openai/">API compatible con OpenAI</a></td><td>Estrategias de implementación para <code>/v1/chat/completions</code> y <code>/v1/responses</code>, permitiendo integración transparente con OpenAI SDK</td></tr><tr><td><a href="./anthropic/">API compatible con Anthropic</a></td><td>Contratos clave de <code>/v1/messages</code> y Claude Code, soportando capacidades como chain-of-thought y system prompts</td></tr><tr><td><a href="./gemini/">API nativa de Gemini</a></td><td>Puntos de conexión <code>/v1beta/models</code> y Google SDK, con compatibilidad <code>x-goog-api-key</code></td></tr><tr><td><a href="./imagen/">Generación de imágenes Imagen 3</a></td><td>Mapeo automático de parámetros <code>size</code>/<code>quality</code> de OpenAI Images, soportando cualquier relación de aspecto</td></tr><tr><td><a href="./audio/">Transcripción de audio</a></td><td>Limitaciones de <code>/v1/audio/transcriptions</code> y manejo de payloads grandes</td></tr><tr><td><a href="./mcp/">Endpoints MCP</a></td><td>Exponer Web Search/Reader/Vision como herramientas invocables</td></tr><tr><td><a href="./cloudflared/">Túnel Cloudflared</a></td><td>Exponer de forma segura la API local a internet con un solo clic (no es seguro por defecto)</td></tr></tbody></table><h2 id="ruta-de-aprendizaje-recomendada" tabindex="-1">Ruta de aprendizaje recomendada <a class="header-anchor" href="#ruta-de-aprendizaje-recomendada" aria-label="Permalink to &quot;Ruta de aprendizaje recomendada&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Orden recomendado</p><ol><li><strong>Primero aprende el protocolo que uses</strong>: Si usas Claude Code, revisa primero <a href="./anthropic/">API compatible con Anthropic</a>; si usas OpenAI SDK, revisa primero <a href="./openai/">API compatible con OpenAI</a></li><li><strong>Luego aprende Gemini nativo</strong>: Conoce el método de integración directa con Google SDK</li><li><strong>Aprende funciones extendidas según necesidad</strong>: Generación de imágenes, transcripción de audio, herramientas MCP</li><li><strong>Finalmente aprende túneles</strong>: Consulta <a href="./cloudflared/">Túnel Cloudflared</a> solo cuando necesites exposición pública</li></ol></div><p><strong>Selección rápida</strong>:</p><table tabindex="0"><thead><tr><th>Tu escenario</th><th>Empieza con</th></tr></thead><tbody><tr><td>Usas Claude Code CLI</td><td><a href="./anthropic/">API compatible con Anthropic</a></td></tr><tr><td>Usas OpenAI Python SDK</td><td><a href="./openai/">API compatible con OpenAI</a></td></tr><tr><td>Usas Google SDK oficial</td><td><a href="./gemini/">API nativa de Gemini</a></td></tr><tr><td>Necesitas generar imágenes con IA</td><td><a href="./imagen/">Generación de imágenes Imagen 3</a></td></tr><tr><td>Necesitas transcripción de voz a texto</td><td><a href="./audio/">Transcripción de audio</a></td></tr><tr><td>Necesitas búsqueda en web/lectura de páginas</td><td><a href="./mcp/">Endpoints MCP</a></td></tr><tr><td>Necesitas acceso remoto</td><td><a href="./cloudflared/">Túnel Cloudflared</a></td></tr></tbody></table><h2 id="requisitos-previos" tabindex="-1">Requisitos previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de comenzar, confirma que</p><ul><li>Has completado <a href="./../start/installation/">Instalación y actualización</a></li><li>Has completado <a href="./../start/add-account/">Agregar cuenta</a></li><li>Has completado <a href="./../start/proxy-and-first-client/">Iniciar proxy inverso local</a> (puedes acceder al menos a <code>/healthz</code>)</li></ul></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar con:</p><ul><li><a href="./../advanced/">Configuración avanzada</a>: funciones avanzadas como enrutamiento de modelos, gestión de cuotas y programación de alta disponibilidad</li><li><a href="./../faq/">Preguntas frecuentes</a>: guía de solución de problemas para errores como 401/404/429</li></ul>',13)])])}const h=a(r,[["render",n]]);export{u as __pageData,h as default};
